const row = $input.first().json;

function mdToHtml(md) {
  if (!md) return '';
  const lines = md.split(/\r?\n/);
  const out = [];
  let inList = false;
  const flushList = () => { if (inList) { out.push('</ul>'); inList = false; } };
  const inline = (s) => s
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/\*(.+?)\*/g, '<em>$1</em>')
    .replace(/`(.+?)`/g, '<code>$1</code>');
  for (const raw of lines) {
    const l = raw.trim();
    if (!l) { flushList(); continue; }
    let m;
    if ((m = l.match(/^#{1,6}\s+(.+)$/))) {
      flushList();
      const lvl = Math.min((l.match(/^#+/) || [''])[0].length, 6);
      out.push('<h' + lvl + '>' + inline(m[1]) + '</h' + lvl + '>');
    } else if ((m = l.match(/^[-*]\s+(.+)$/))) {
      if (!inList) { out.push('<ul>'); inList = true; }
      out.push('<li>' + inline(m[1]) + '</li>');
    } else {
      flushList();
      out.push('<p>' + inline(l) + '</p>');
    }
  }
  flushList();
  return out.join('\n');
}

const bodyHtml = mdToHtml(row.resume_content || '');

const html = `<!DOCTYPE html>
<html>
<head>
<style>
body{font-family:Georgia,serif;margin:40px 60px;color:#1a1a1a;line-height:1.45;font-size:12px}
h1{font-size:22px;margin:0 0 4px 0;color:#111;font-family:-apple-system,sans-serif;font-weight:700}
h2{font-size:14px;margin:18px 0 6px 0;color:#222;font-family:-apple-system,sans-serif;font-weight:700;border-bottom:1px solid #ddd;padding-bottom:2px;text-transform:uppercase;letter-spacing:0.5px}
h3{font-size:13px;margin:10px 0 4px 0;color:#222;font-family:-apple-system,sans-serif;font-weight:600}
h4,h5,h6{font-size:12px;margin:6px 0 2px 0;font-weight:600}
p{margin:4px 0;text-align:justify}
ul{margin:4px 0;padding-left:20px}
li{margin:2px 0}
strong{font-weight:700}
em{font-style:italic}
code{font-family:Menlo,Consolas,monospace;font-size:11px;background:#f4f4f4;padding:1px 3px;border-radius:2px}
</style>
</head>
<body>
${bodyHtml}
</body>
</html>`;

return [{
  json: {
    job_id: row.job_id,
    title: row.title,
    company: row.company,
    tailored_resume_id: row.tailored_resume_id
  },
  binary: {
    data: {
      data: Buffer.from(html, 'utf8').toString('base64'),
      mimeType: 'text/html',
      fileName: 'resume.html',
      fileExtension: 'html'
    }
  }
}];

const meta = $('Build Resume HTML').first().json;
const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
if (!buf || !buf.length) {
  throw new Error('Resume PDF generation failed: Stirling returned empty binary');
}
return [{
  json: {
    job_id: meta.job_id,
    title: meta.title,
    company: meta.company,
    tailored_resume_id: meta.tailored_resume_id,
    pdf_base64: buf.toString('base64')
  }
}];
